-- Program: Ultimate Strength
-- Category: Strength -> strength
-- Priority: High
-- Durations: [12], Sessions: [4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Ultimate Strength',
    'An advanced 12-week periodized strength program with 4 distinct phases: Accumulation (volume), Intensification (heavy loads), Realization (heavy singles practice), and Peak Testing (1RM attempts). Uses upper/lower split with competition-style lift preparation.',
    'strength',
    'advanced',
    12,
    4,
    'upper_lower',
    ARRAY['Increase maximal strength', 'Progressive overload']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Ultimate Strength - 12w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    12,
    'Ultimate Strength - 12w 4x/wk',
    'strength',
    4,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Ultimate Strength'
ON CONFLICT DO NOTHING;

