onds": 180, "weight_guidance": "70% conventional 1RM, RPE 7", "equipment": "Barbell", "body_part": "Legs", "primary_muscle": "Glutes", "secondary_muscles": ["Hamstrings", "Adductors", "Quadriceps"], "difficulty": "advanced", "form_cue": "Wide stance, toes out, chest up, push knees out", "substitution": "Conventional Deadlift"}, {"name": "Bulgarian Split Squat", "exercise_library_id": null, "in_library": false, "sets": 4, "reps": 8, "rest_seconds": 90, "weight_guidance": "Moderate dumbbells, each leg", "equipment": "Dumbbells", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Glutes", "Hamstrings"], "difficulty": "advanced", "form_cue": "Rear foot elevated, deep stretch, drive through front heel", "substitution": "Walking Lunge"}, {"name": "Glute-Ham Raise", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 8, "rest_seconds": 90, "weight_guidance": "Bodyweight, control eccentric", "equipment": "GHD", "body_part": "Legs", "primary_muscle": "Hamstrings", "secondary_muscles": ["Glutes", "Calves"], "difficulty": "advanced", "form_cue": "Slow lower, use hamstrings to pull back up", "substitution": "Nordic Curl"}, {"name": "Leg Extension", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 60, "weight_guidance": "Moderate, pause at top", "equipment": "Machine", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": [], "difficulty": "advanced", "form_cue": "Full extension, 2-second squeeze at top", "substitution": "Sissy Squat"}, {"name": "Seated Calf Raise", "exercise_library_id": null, "in_library": false, "sets": 4, "reps": 15, "rest_seconds": 60, "weight_guidance": "Moderate, full range", "equipment": "Machine", "body_part": "Legs", "primary_muscle": "Soleus", "secondary_muscles": ["Calves"], "difficulty": "advanced", "form_cue": "Deep stretch at bottom, full contraction at top", "substitution": "Standing Calf Raise"}, {"name": "Ab Wheel Rollout", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 60, "weight_guidance": "Bodyweight, full extension", "equipment": "Ab Wheel", "body_part": "Core", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Obliques", "Erector Spinae"], "difficulty": "advanced", "form_cue": "Controlled extension, brace core throughout", "substitution": "Plank"}]}]'::jsonb,
    'Ultimate Strength',
    'Ultimate Strength - 12w 4x/wk',
    'High',
    false,
    'An advanced 12-week periodized strength program with 4 distinct phases: Accumulation (volume), Intensification (heavy loads), Realization (heavy singles practice), and Peak Testing (1RM attempts). Uses upper/lower split with competition-style lift preparation.',
    'Strength'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
